5	const BEAD_QUERY = gql`
6		query Bead($id: ID!, $projectID: String!) {
7			bead(id: $id) {
8				id
9				title
10				status
11				priority
12				issueType
13				owner
14				createdAt
15				createdBy
16				updatedAt
17				labels
18				parent
19				description
20				acceptance
21				notes
22				dependencies {
23					issueId
24					dependsOnId
25					type
26					createdAt
27					createdBy
28				}
29			}
30			projectBeads: beadsByProject(projectID: $projectID, first: 500) {
31				edges {
32					node {
33						id
34						parent
35					}
36				}
37			}
38			beadExecutions: executions(projectId: $projectID, beadId: $id, first: 50) {
39				edges {
40					node {
41						id
42						verdict
43						harness
44						createdAt
45						durationMs
46						costUsd
47					}
48				}
49				totalCount
50			}
51		}
52	`;
